        // WebSocket client - RFC 6455 implementation using PHP streams
        // Returns structured data with frames received or error info.

        // Helper: encode a WebSocket data frame (text or binary, FIN set)
        $encodeFrame = function($data, $opcode) {
            $len = strlen($data);
            $frame = chr(0x80 | $opcode); // FIN + opcode
            if ($len < 126) {
